code = """import json, re

def extract_owner_repo(s: str):
    # prefer owner/repo on 'project <owner/repo>'
    m = re.search(r'project\s+(?:named\s+)?([A-Za-z0-9_.-]+/[A-Za-z0-9_.-]+)', s, flags=re.I)
    if m:
        return m.group(1)
    m = re.search(r'name\s+learnfrontend-dc/product-cart', s, flags=re.I)
    if m:
        return 'learnfrontend-dc/product-cart'
    return None

def extract_forks(s: str):
    # patterns: 'and X forks' or 'forks, making' or 'forked X times'
    m = re.search(r'\b([0-9][0-9,]*)\s+forks\b', s, flags=re.I)
    if m:
        return int(m.group(1).replace(',',''))
    m = re.search(r'forked\s+([0-9][0-9,]*)\s+times', s, flags=re.I)
    if m:
        return int(m.group(1).replace(',',''))
    return None

sample = var_call_DzcaMvQsRlDChrttgvbClpff
out=[]
for r in sample:
    s=r['Project_Information']
    out.append({'repo': extract_owner_repo(s), 'forks': extract_forks(s), 'text': s})

print('__RESULT__:')
print(json.dumps(out[:10]))"""

